const LocalDataManager = () => {
  
  return {
    store(key, data) {
      try{
        AsyncStorage.setItem(`${key}`, JSON.stringify(data))
        return true;
      } catch (error){
        return false;
      }
      
    },

    get(key) {
      
      return AsyncStorage.getItem(`${key}`);
    },
    delete(key) {
      
      return AsyncStorage.removeItem(key);
    }
  }
}

